=You are an invoice detection system. Analyze the following email and determine if it's likely to contain an invoice. The email subject is: "{{$node["Microsoft Outlook"].json["subject"]}}" and the email body is: "{{$node["Microsoft Outlook"].json["bodyPreview"]}}". 

Also consider these attachment names if any: {{$node["Microsoft Outlook"].json["hasAttachments"] ? $node["Microsoft Outlook"].json["attachments"].map(a => a.name).join(", ") : "No attachments"}}

Respond only with a JSON object with the following structure:
{
  "isInvoice": true/false,
  "confidence": 0-1 (probability score),
  "reasoning": "your reasoning here"
}

parameters.jsCode:
// Get relevant data from previous nodes
const invoice = $node["HTTP Request1"].json.Invoices[0];
const transactions = $node["HTTP Request2"].json.BankTransactions;
const exchangeRates = $node["HTTP Request"].json.rates;

// Reconciliation logic
const possibleMatches = [];

// Convert amount to invoice currency if needed
function convertCurrency(amount, fromCurrency, toCurrency) {
  if (fromCurrency === toCurrency) return amount;

  // Convert through the base currency
  const invoiceCurrencyRate = exchangeRates[toCurrency] || 1;
  const txCurrencyRate = exchangeRates[fromCurrency] || 1;

  return amount * (invoiceCurrencyRate / txCurrencyRate);
}

// Calculate days between two dates
function daysBetween(date1, date2) {
  const d1 = new Date(date1);
  const d2 = new Date(date2);
  const diffTime = Math.abs(d2 - d1);
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  return diffDays;
}

// Check each transaction for a match
for (const tx of transactions) {
  // Skip deposits (we're looking for payments)
  if (tx.Type !== "SPEND") continue;

  // Convert transaction amount to invoice currency
  const txAmount = Math.abs(tx.Total);
  const txCurrency = tx.CurrencyCode || "USD"; // Default if not specified
  const invoiceAmount = invoice.Total;
  const invoiceCurrency = invoice.CurrencyCode;

  const convertedAmount = convertCurrency(txAmount, txCurrency, invoiceCurrency);

  // Check if amounts match (with small tolerance for rounding issues)
  const amountMatch = Math.abs(convertedAmount - invoiceAmount) < 0.02;

  // Check if dates are reasonably close (within 30 days)
  const dateDiff = daysBetween(tx.Date, invoice.Date);
  const dateMatch = dateDiff <= 30;

  // Add to possible matches if both criteria met
  if (amountMatch && dateMatch) {
    possibleMatches.push({
      transactionId: tx.BankTransactionID,
      date: tx.Date,
      amount: tx.Total,
      currency: txCurrency,
      convertedAmount: convertedAmount,
      dateDifference: dateDiff
    });
  }
}

// Sort matches by date proximity (closest first)
possibleMatches.sort((a, b) => a.dateDifference - b.dateDifference);

// Return the result
return {
  json: {
    invoice: invoice,
    possibleMatches: possibleMatches,
    // Add a selected match if we found any
    selectedMatch: possibleMatches.length > 0 ? possibleMatches[0] : null
  }
};

