// Evaluate which attachment is most likely to be the invoice
function getInvoiceAttachment(attachments, invoiceNumber) {
  if (!attachments || attachments.length === 0) {
    return null;
  }

  // If there's only one attachment, return it
  if (attachments.length === 1) {
    return attachments[0];
  }

  // Check for PDF files first
  const pdfAttachments = attachments.filter(a => 
    a.contentType === 'application/pdf' || 
    a.name.toLowerCase().endsWith('.pdf')
  );

  if (pdfAttachments.length === 1) {
    return pdfAttachments[0];
  }

  // Look for attachments with 'invoice' in the name
  const invoiceAttachments = attachments.filter(a => 
    a.name.toLowerCase().includes('invoice')
  );

  if (invoiceAttachments.length > 0) {
    return invoiceAttachments[0];
  }

  // If we have an invoice number, look for attachments with that number
  if (invoiceNumber) {
    const matchingAttachments = attachments.filter(a => 
      a.name.includes(invoiceNumber)
    );

    if (matchingAttachments.length > 0) {
      return matchingAttachments[0];
    }
  }

  // Default to the first attachment if we couldn't find a better match
  return attachments[0];
}

// Get the best attachment
const attachments = $node["Microsoft Outlook"].json.attachments;
const invoiceNumber = $node["OpenAI1"].json.invoiceNumber;
const bestAttachment = getInvoiceAttachment(attachments, invoiceNumber);

return { json: { bestAttachment } };

